#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* next;
    Node(int x) : val(x), next(NULL) {}
};

Node* create_linked_list(vector<int>& nums) {
    Node* head = new Node(nums[0]);
    Node* current = head;
    for (int i = 1; i < nums.size(); i++) {
        current->next = new Node(nums[i]);
        current = current->next;
    }
    return head;
}

Node* delete_node(Node* head, int target) {
    if (head->val == target) {
        Node* temp = head;
        head = head->next;
        delete temp;
        return head;
    }
    Node* current = head;
    while (current->next) {
        if (current->next->val == target) {
            Node* temp = current->next;
            current->next = current->next->next;
            delete temp;
            return head;
        }
        current = current->next;
    }
    return head;
}

void print_linked_list(Node* head) {
    while (head) {
        cout << head->val << ' ';
        head = head->next;
    }
    cout << endl;
}

int main() {
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int target; cin >> target;
    Node* head = create_linked_list(nums);
    head = delete_node(head, target);
    print_linked_list(head);
    return 0;
}
